"-- ============================================================================\n-- LitOps: Admin Create User RPC Function\n-- RUN THIS IN SUPABASE SQL EDITOR\n-- Dashboard > SQL Editor > New Query > Paste this > Click RUN\n-- ============================================================================\n-- This function allows the Super Admin to create new user accounts.\n-- It inserts into both auth.users and profiles in a single transaction.\n-- ============================================================================\n\nCREATE OR REPLACE FUNCTION admin_create_user(\n  p_email TEXT,\n  p_password TEXT,\n  p_full_name TEXT,\n  p_role TEXT DEFAULT 'junior_wing',\n  p_phone TEXT DEFAULT NULL,\n  p_year INTEGER DEFAULT NULL,\n  p_usn TEXT DEFAULT NULL,\n  p_date_of_birth TEXT DEFAULT NULL\n)\nRETURNS UUID AS $$\nDECLARE\n  caller_role TEXT;\n  new_user_id UUID;\nBEGIN\n  -- 1. Verify the caller is a super_admin\n  SELECT role::TEXT INTO caller_role\n  FROM profiles\n  WHERE id = auth.uid() AND is_active = true;\n\n  IF caller_role IS NULL OR caller_role != 'super_admin' THEN\n    RAISE EXCEPTION 'Permission denied: only super_admin can create user accounts.';\n  END IF;\n\n  -- 2. Validate required fields\n  IF p_email IS NULL OR p_email = '' THEN\n    RAISE EXCEPTION 'Email is required.';\n  END IF;\n  IF p_password IS NULL OR length(p_password) < 6 THEN\n    RAISE EXCEPTION 'Password must be at least 6 characters.';\n  END IF;\n  IF p_full_name IS NULL OR p_full_name = '' THEN\n    RAISE EXCEPTION 'Full name is required.';\n  END IF;\n\n  -- 3. Check if email already exists\n  IF EXISTS (SELECT 1 FROM auth.users WHERE email = p_email) THEN\n    RAISE EXCEPTION 'A user with this email already exists.';\n  END IF;\n\n  -- 4. Generate a new UUID for the user\n  new_user_id := uuid_generate_v4();\n\n  -- 5. Insert into auth.users\n  INSERT INTO auth.users (\n    id, aud, role, email, encrypted_password,\n    email_confirmed_at, raw_app_meta_data, raw_user_meta_data,\n    created_at, updated_at, instance_id,\n    
